import{_ as r,c as l,o as t,a5 as i,j as a}from"./chunks/framework.Dtwt352Q.js";const k=JSON.parse('{"title":"v1.1.36：启用 Thinking 模式，多项 UI 改进","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.36.md","filePath":"changelog/v1.1.36.md","lastUpdated":1772014034000}'),n={name:"changelog/v1.1.36.md"};function h(o,e,s,d,c,p){return t(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="v1-1-36-启用-thinking-模式-多项-ui-改进" tabindex="-1">v1.1.36：启用 Thinking 模式，多项 UI 改进 <a class="header-anchor" href="#v1-1-36-启用-thinking-模式-多项-ui-改进" aria-label="Permalink to “v1.1.36：启用 Thinking 模式，多项 UI 改进”">​</a></h1><p><strong>发布日期</strong>：2026年01月25日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新为 Google Vertex Anthropic 模型启用了 Thinking 模式，并改进了 TUI 和 Desktop 的多项细节。</p><hr><h2 id="新功能-thinking-模式支持" tabindex="-1">新功能：Thinking 模式支持 <a class="header-anchor" href="#新功能-thinking-模式支持" aria-label="Permalink to “新功能：Thinking 模式支持”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>现在使用 Google Vertex AI 的 Anthropic 模型时，可以使用 Thinking 模式，让模型展示其思考过程。</p><h3 id="thinking-模式是什么" tabindex="-1">Thinking 模式是什么？ <a class="header-anchor" href="#thinking-模式是什么" aria-label="Permalink to “Thinking 模式是什么？”">​</a></h3><p>Thinking 模式允许 AI 模型在生成最终答案前展示其思考过程，这对于复杂问题的理解和调试非常有帮助。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><ol><li>确保你使用的是 Google Vertex AI 的 Anthropic 模型</li><li>在请求中包含 thinking 参数</li><li>模型会先展示思考过程，再给出最终答案</li></ol><hr><h2 id="问题修复-主题搜索崩溃" tabindex="-1">问题修复：主题搜索崩溃 <a class="header-anchor" href="#问题修复-主题搜索崩溃" aria-label="Permalink to “问题修复：主题搜索崩溃”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>在 TUI 中搜索主题时，如果没有匹配结果会导致崩溃。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>感谢社区贡献者 @ishaksebsib 的修复，现在搜索无结果时会正常显示提示，而不会崩溃。</p><hr><h2 id="问题修复-下载按钮" tabindex="-1">问题修复：下载按钮 <a class="header-anchor" href="#问题修复-下载按钮" aria-label="Permalink to “问题修复：下载按钮”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>Web 界面的下载按钮缺失或无法正常工作。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复并完善了下载按钮的功能。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用 Google Vertex Anthropic</td><td>✅ 强烈推荐</td></tr><tr><td>使用 TUI</td><td>✅ 推荐升级（修复崩溃问题）</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',29),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Enable thinking for Google Vertex Anthropic models (@MichaelYochpaz)</li><li>Make question validation more lax to avoid tool call failures</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Prevent crash when theme search returns no results (@ishaksebsib)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Visual cleanup in app</li><li>Scroll to comment on click in app</li><li>Fixed crash when no default model is set</li><li>Performance improvements in the app package</li><li>Clean up comment component usage in app</li></ul><p><strong>Thank you to 5 community contributors:</strong></p><p>@MichaelYochpaz:</p><ul><li>fix(provider): enable thinking for google-vertex-anthropic models (#10442)</li></ul><p>@ProdigyRahul:</p><ul><li>fix(app): cursor on resize (#10293)</li></ul><p>@DNGriffin:</p><ul><li>fix(app): mobile horizontal scrolling due to session stat btn (#10487)</li></ul><p>@ishaksebsib:</p><ul><li>fix(tui): prevent crash when theme search returns no results (#10565)</li></ul><p>@R44VC0RP:</p><ul><li>fix(web): add &amp; fix the download button (#10566)</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const u=r(n,[["render",h]]);export{k as __pageData,u as default};
